class Solution {
    public boolean canConvertString(String s, String t, int k) {
        if (s.length() != t.length()) return false;
        int[] count = new int[26];
        for (int i = 0; i < s.length(); i++) {
            int diff = Math.abs(t.charAt(i) - s.charAt(i));
            if (diff == 0) continue;
            if (diff > 26 - diff) {
                if (k < diff - 1) return false;
                k -= diff - 1;
            }
            count[diff - 1]++;
        }
        for (int i = 0; i < 26; i++) {
            if (count[i] > k / (i + 1)) return false;
        }
        return true;
    }
}
